import React, { useState } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { authService } from "../services";
import Sidebar from "../components/Sidebar";
import { getAdminMenuItems } from "../config/menuConfig";
import "../styles/Dashboard.css";

const AdminDashboard = () => {
  const user = authService.getCurrentUser();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const handleLogout = () => {
    authService.logout();
    navigate("/admin/login");
  };

  const menuItems = getAdminMenuItems(navigate);

  const isActive = (path) => location.pathname === path;

  return (
    <div className="dashboard-container">
      <Sidebar
        sidebarOpen={sidebarOpen}
        setSidebarOpen={setSidebarOpen}
        menuItems={menuItems}
        isActive={isActive}
        handleLogout={handleLogout}
        sidebarTitle="🛡️ Admin"
      />

      {/* Main Content */}
      <main className="dashboard-main">
        <div className="dashboard-content">
          <div className="info-card admin-info">
            <h3>Admin Control Panel</h3>
            <p>Control and manage the load management system.</p>
            <ul>
              <li>Create and manage loads</li>
              <li>Track load status</li>
              <li>View all available loads</li>
              <li>Edit or delete loads</li>
              <li>Monitor system activity</li>
              <li>Admin user management</li>
            </ul>
            <button onClick={() => navigate("/loads")} className="btn-primary">
              View All Loads
            </button>
          </div>

          <div className="quick-stats">
            <div className="stat-card">
              <h4>Email</h4>
              <p>{user?.email}</p>
            </div>
            <div className="stat-card">
              <h4>Role</h4>
              <p className="role-badge admin-badge">
                {user?.role?.toUpperCase()}
              </p>
            </div>
            <div className="stat-card">
              <h4>Access Level</h4>
              <p>Full Administrative Access</p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
